-- Add PushPress plans not in original setup
ON CONFLICT (id) DO NOTHING;

ALTER TABLE members ADD COLUMN IF NOT EXISTS pushpress_id TEXT;
ALTER TABLE members ADD COLUMN IF NOT EXISTS plan_name TEXT;

-- Temporary import table for PushPress members
CREATE TABLE IF NOT EXISTS pushpress_members (
  id              UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  pushpress_id    TEXT,
  email           TEXT NOT NULL,
  full_name       TEXT NOT NULL,
  phone           TEXT,
  plan_id         TEXT DEFAULT 'other',
  plan_name       TEXT,
  status          TEXT DEFAULT 'active',
  member_since    DATE,
  imported_at     TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE pushpress_members ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "pp_members_admin" ON pushpress_members;
CREATE POLICY "pp_members_admin" ON pushpress_members FOR ALL
  USING (EXISTS (SELECT 1 FROM members WHERE id = auth.uid() AND role = 'admin'));
DROP POLICY IF EXISTS "pp_members_select" ON pushpress_members;
CREATE POLICY "pp_members_select" ON pushpress_members FOR SELECT USING (true);

-- Billing history from PushPress
CREATE TABLE IF NOT EXISTS billing_history (
  id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  email       TEXT NOT NULL,
  name        TEXT,
  date        DATE,
  subtotal    DECIMAL(10,2),
  tax_amount  DECIMAL(10,2),
  total       DECIMAL(10,2),
  item        TEXT,
  receipt     TEXT,
  source      TEXT DEFAULT 'pushpress',
  created_at  TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE billing_history ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "billing_admin" ON billing_history;
CREATE POLICY "billing_admin" ON billing_history FOR SELECT
  USING (EXISTS (SELECT 1 FROM members WHERE id = auth.uid() AND role = 'admin'));
DROP POLICY IF EXISTS "billing_own" ON billing_history;
CREATE POLICY "billing_own" ON billing_history FOR SELECT
  USING (email = (SELECT email FROM members WHERE id = auth.uid()));

