-- ═══ INSERT TRANSACTIONS ═══





-- Auto-link PushPress data when a member creates an account
CREATE OR REPLACE FUNCTION public.link_pushpress_data()
RETURNS TRIGGER AS $$
DECLARE pp RECORD;
BEGIN
  SELECT * INTO pp FROM pushpress_members WHERE LOWER(email) = LOWER(NEW.email) LIMIT 1;
  IF FOUND THEN
    UPDATE members SET
      plan_id = pp.plan_id,
      plan_name = pp.plan_name,
      phone = COALESCE(pp.phone, members.phone),
      member_since = pp.member_since,
      pushpress_id = pp.pushpress_id
    WHERE id = NEW.id;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS on_member_created_link_pp ON members;
CREATE TRIGGER on_member_created_link_pp
  AFTER INSERT ON members
  FOR EACH ROW EXECUTE FUNCTION public.link_pushpress_data();

